// Universal Smart Message Router - Handle 'message', 'message.any', AND 'engine.event' events
// UPDATED: Handle data from router (Execute Workflow) - checks original_payload first
// ADDED: Deduplication - skip direct webhook if already processed by router
// CRITICAL: Store 'this' reference at top level to preserve context
const self = this;
const items = $input.all();
const results = [];

console.log('[Router] ===== STARTING ROUTER (V2 ROBUST) =====');
console.log('[Router] Input items count:', items.length);

// Use 'global' scope so other nodes can access this data
let staticData;
try {
  staticData = self.getWorkflowStaticData('global');
} catch (error) {
  staticData = {};
}

// Use arrays instead of Sets to avoid serialization issues
staticData.processedMessageIds = staticData.processedMessageIds || [];
staticData.processedMessageTimestamps = staticData.processedMessageTimestamps || {};
staticData.rateLimitTracker = staticData.rateLimitTracker || {};

// Deduplication: Check if message was already processed
if (!staticData.processedMessages) {
  staticData.processedMessages = {};
}

const now = Date.now();

// Helper: Recursively find text content in object
const findTextContent = (obj, depth = 0) => {
  if (!obj || typeof obj !== 'object' || depth > 5) return null;

  // Direct checks
  if (obj.caption) return obj.caption;
  if (obj.conversation) return obj.conversation;
  if (obj.text && typeof obj.text === 'string') return obj.text;

  // Recursive search
  for (const key in obj) {
    if (key === 'contextInfo' || key === 'quotedMessage') continue; // Skip quoted messages
    const res = findTextContent(obj[key], depth + 1);
    if (res) return res;
  }
  return null;
};

// STRICT check-and-mark function
const tryMarkAsProcessed = (keys) => {
  if (!Array.isArray(keys) || keys.length === 0) return false;
  const processed = staticData.processedMessageIds;
  const timestamps = staticData.processedMessageTimestamps;
  const now = Date.now();

  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];
    if (key && processed.includes(key)) {
      console.log('[Router] ⏭️ Skipping duplicate message:', key);
      return false;
    }
  }

  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];
    if (key && !processed.includes(key)) {
      processed.push(key);
      timestamps[key] = now;
    }
  }

  // Cleanup
  if (processed.length > 1000) {
    const oldKeys = processed.slice(0, processed.length - 1000);
    processed.splice(0, processed.length - 1000);
    for (let i = 0; i < oldKeys.length; i++) {
      delete timestamps[oldKeys[i]];
    }
  }
  return true;
};

const checkRateLimit = (userId, maxMessages, windowMs) => {
  maxMessages = maxMessages || 10;
  windowMs = windowMs || 60000;
  const now = Date.now();
  const tracker = staticData.rateLimitTracker;

  if (!tracker[userId]) tracker[userId] = [];

  const recentMessages = tracker[userId].filter(t => now - t < windowMs);
  tracker[userId] = recentMessages;

  if (recentMessages.length >= maxMessages) return false;

  tracker[userId].push(now);
  return true;
};

// Helper: Extract message data
// UPDATED: Handle data from router (Execute Workflow) - checks original_payload first
// ADDED: Deduplication check for direct webhooks
const extractMessageData = (item) => {
  const msg = item.json || {};

  // CRITICAL: Handle data from router (Execute Workflow) - router passes original_payload
  // Also handle direct WAHA trigger format (payload) and webhook format
  let payload = msg.original_payload || msg.payload || {};
  const eventType = msg.event || 'message';

  // CRITICAL: Handle direct webhook format (body.payload)
  if (msg.body?.payload && !msg.original_payload) {
    // This is a direct webhook (not from router)
    payload = msg.body.payload;
    const messageId = payload.id || '';
    const timestamp = payload.timestamp || 0;
    const processedKey = `${messageId}_${timestamp}`;

    // Check if router already processed this message (within last 10 seconds)
    if (staticData.processedMessages[processedKey]) {
      const processedTime = staticData.processedMessages[processedKey];
      const timeDiff = now - processedTime;

      if (timeDiff < 10000) { // 10 seconds
        console.log(`[Router] ⏭️ Skipping duplicate direct webhook (processed ${timeDiff}ms ago):`, messageId);
        return null; // Skip - already processed by router
      }
    }

    // Mark as processed
    staticData.processedMessages[processedKey] = now;
    console.log(`[Router] ✅ Processing direct webhook message:`, messageId);
  } else if (msg.original_payload) {
    // This is from router (Execute Workflow) - mark as processed
    const messageId = payload.id || '';
    const timestamp = payload.timestamp || 0;
    const processedKey = `${messageId}_${timestamp}`;
    staticData.processedMessages[processedKey] = now;
    console.log(`[Router] ✅ Processing router message:`, messageId);
  }

  // Cleanup old entries (older than 60 seconds)
  for (const key in staticData.processedMessages) {
    if (now - staticData.processedMessages[key] > 60000) {
      delete staticData.processedMessages[key];
    }
  }

  // CRITICAL: Skip non-message events (session.status, etc.)
  if (eventType !== 'message' && eventType !== 'message.any' && eventType !== 'engine.event') {
    console.log('[Router] ⏭️ Skipping non-message event:', eventType);
    return null;
  }

  if (eventType === 'message' || eventType === 'message.any') {
    return {
      payload: payload,
      _data: payload._data || {},
      fromMe: payload.fromMe || false
    };
  }

  if (eventType === 'engine.event') {
    let messageData;
    if (payload.event === 'messages.upsert') {
      messageData = payload.data?.messages?.[0];
    } else if (payload.event === 'chats.update') {
      messageData = payload.data?.[0]?.messages?.[0]?.message; // Structure varies
    }

    if (messageData) {
      const key = messageData.key || {};
      const message = messageData.message || {};

      // ROBUST: Use recursive finder
      const body = findTextContent(message) || '';

      return {
        payload: {
          id: key.id || '',
          from: key.remoteJid || '',
          fromMe: key.fromMe || false,
          timestamp: messageData.messageTimestamp || Date.now(),
          body: body,
          hasMedia: !!(message.imageMessage || message.videoMessage || message.documentMessage || message.audioMessage),
          media: message.imageMessage ? { url: message.imageMessage.url, mimetype: message.imageMessage.mimetype } : null,
          _data: { key, messageTimestamp: messageData.messageTimestamp, message }
        },
        _data: { key, messageTimestamp: messageData.messageTimestamp, message },
        fromMe: key.fromMe || false
      };
    }
  }
  return null;
};

for (let itemIndex = 0; itemIndex < items.length; itemIndex++) {
  const item = items[itemIndex];
  const messageData = extractMessageData(item);
  if (!messageData) continue;

  const payload = messageData.payload || {};
  const _data = messageData._data || {};

  if (messageData.fromMe === true) continue;

  const _dataKey = _data.key || {};
  const actualMessageId = _dataKey.id || payload.id || '';
  const compositeId = payload.id || '';
  const remoteJid = payload.from || _dataKey.remoteJid || '';
  const userId = remoteJid ? String(remoteJid).replace('@s.whatsapp.net', '@c.us') : '';
  const timestamp = payload.timestamp || _data.messageTimestamp || Date.now();

  const dedupKeys = [actualMessageId, compositeId].filter(k => k);

  try { self.setWorkflowStaticData('global', staticData); } catch (e) {}
  if (!tryMarkAsProcessed(dedupKeys)) continue;
  try { self.setWorkflowStaticData('global', staticData); } catch (e) {}

  if (userId && !checkRateLimit(userId)) continue;

  let messageType = 'text';

  // ROBUST: Use recursive finder for text content
  let textContent = payload.body || '';
  if (!textContent && _data.message) {
    textContent = findTextContent(_data.message) || '';
  }

  let mediaUrl = '';
  let mediaInfo = {};

  const _dataMessage = _data.message || {};
  const audioMsg = _dataMessage.audioMessage || null;

  if (payload.hasMedia === true || _dataMessage.imageMessage || _dataMessage.videoMessage || _dataMessage.documentMessage || _dataMessage.audioMessage) {
    if (audioMsg || _dataMessage.audioMessage) {
      const audio = audioMsg || _dataMessage.audioMessage;
      messageType = 'voice';
      mediaUrl = (payload.media && payload.media.url) || audio.url || '';
      mediaInfo = { isPTT: audio.ptt === true, mimetype: audio.mimetype || 'audio/ogg' };
    } else if (_dataMessage.imageMessage) {
      messageType = 'image';
      mediaUrl = _dataMessage.imageMessage.url || '';
      mediaInfo = { mimetype: _dataMessage.imageMessage.mimetype || 'image/jpeg' };
    } else if (_dataMessage.videoMessage) {
      messageType = 'video';
      mediaUrl = _dataMessage.videoMessage.url || '';
      mediaInfo = { mimetype: _dataMessage.videoMessage.mimetype || 'video/mp4' };
    } else if (_dataMessage.documentMessage) {
      messageType = 'document';
      mediaUrl = _dataMessage.documentMessage.url || '';
      mediaInfo = { mimetype: _dataMessage.documentMessage.mimetype || 'application/pdf' };
    }
  } else if (_dataMessage.ptt === true) {
    messageType = 'voice';
    if (audioMsg && audioMsg.url) mediaUrl = audioMsg.url;
    mediaInfo = { isPTT: true, mimetype: audioMsg ? audioMsg.mimetype : 'audio/ogg' };
  }

  // Fix localhost URLs
  if (mediaUrl && mediaUrl.includes('localhost')) {
    mediaUrl = mediaUrl.replace('localhost', '173.254.201.134');
  }

  const messageId = actualMessageId || compositeId;

  staticData.lastMessageMetadata = {
    userId: userId,
    messageId: messageId,
    sessionId: userId,
    requiresVoiceResponse: messageType === 'voice',
    source: 'waha',
    store_name: 'fileSearchStores/rensto-knowledge-base-ndf9fmymwb2p'
  };

  try { self.setWorkflowStaticData('global', staticData); } catch (e) {}

  console.log('[Router] ✅ Processed:', messageType, 'ID:', messageId, 'Text:', textContent.substring(0, 50));

  results.push({
    json: {
      messageId: messageId,
      messageType: messageType,
      source: 'waha',
      userId: userId,
      timestamp: timestamp,
      textContent: textContent,
      mediaUrl: mediaUrl,
      mediaInfo: mediaInfo,
      originalPayload: payload,
      requiresVoiceResponse: messageType === 'voice',
      sessionId: userId
    }
  });
}

return results;
